using namespace std;

// Function to run the child process
void run_child(int input_fd, int output_fd) {
    cout << "[Child Process] Starting execution." << endl;

    // 1. Redirect stdin (fd 0) to the input pipe
    if (dup2(input_fd, STDIN_FILENO) == -1) {
        perror("dup2 stdin failed");
        exit(EXIT_FAILURE);
    }

    // 2. Redirect stdout (fd 1) to the output pipe
    if (dup2(output_fd, STDOUT_FILENO) == -1) {
        perror("dup2 stdout failed");
        exit(EXIT_FAILURE);
    }

    // 3. Close the original pipe ends (optional but good practice)
    close(input_fd);
    close(output_fd);

    // 4. Execute the new program
    // We'll use 'cat' here as a simple example, but replace this with your target executable.
    // The arguments should be null-terminated.
    char* argv[] = {"cat", "-n"};

    cout << "[Child Process] Executing 'cat -n'..." << endl;
    if (execvp(argv[0], argv) == -1) {
